scene_js:
// Ribbingintie 109-11, Helsinki — 1980s omakotitalo
// Rectangular 2-story wood-frame house, gable roof, ~10x12m footprint

// Foundation (visible concrete, 0.3m)
const foundation = translate(cube({size: [12, 0.3, 10], center: true}), [0, 0.15, 0]);

// Ground floor walls (2.7m)
const gf_wall_front = translate(cube({size: [12, 2.7, 0.2], center: true}), [0, 1.65, -4.9]);
const gf_wall_back = translate(cube({size: [12, 2.7, 0.2], center: true}), [0, 1.65, 4.9]);
const gf_wall_left = translate(cube({size: [0.2, 2.7, 10], center: true}), [-5.9, 1.65, 0]);
const gf_wall_right = translate(cube({size: [0.2, 2.7, 10], center: true}), [5.9, 1.65, 0]);

// Front door opening
const front_door = translate(cube({size: [1.0, 2.1, 0.3], center: true}), [0, 1.35, -4.9]);
const gf_wall_front_cut = difference(gf_wall_front, front_door);

// Ground floor windows
const gf_win1 = translate(cube({size: [1.2, 1.4, 0.3], center: true}), [-3.0, 1.7, -4.9]);
const gf_win2 = translate(cube({size: [1.2, 1.4, 0.3], center: true}), [3.0, 1.7, -4.9]);
const gf_wall_front_final = difference(difference(gf_wall_front_cut, gf_win1), gf_win2);

// Back wall windows
const gf_bwin1 = translate(cube({size: [1.4, 1.4, 0.3], center: true}), [-3.0, 1.7, 4.9]);
const gf_bwin2 = translate(cube({size: [1.4, 1.4, 0.3], center: true}), [2.0, 1.7, 4.9]);
const gf_wall_back_final = difference(difference(gf_wall_back, gf_bwin1), gf_bwin2);

// First floor slab
const floor1 = translate(cube({size: [12, 0.25, 10], center: true}), [0, 3.125, 0]);

// Upper floor walls (2.7m)
const uf_wall_front = translate(cube({size: [12, 2.7, 0.2], center: true}), [0, 4.6, -4.9]);
const uf_wall_back = translate(cube({size: [12, 2.7, 0.2], center: true}), [0, 4.6, 4.9]);
const uf_wall_left = translate(cube({size: [0.2, 2.7, 10], center: true}), [-5.9, 4.6, 0]);
const uf_wall_right = translate(cube({size: [0.2, 2.7, 10], center: true}), [5.9, 4.6, 0]);

// Upper floor windows
const uf_win1 = translate(cube({size: [1.2, 1.2, 0.3], center: true}), [-3.0, 4.6, -4.9]);
const uf_win2 = translate(cube({size: [1.2, 1.2, 0.3], center: true}), [1.0, 4.6, -4.9]);
const uf_win3 = translate(cube({size: [1.2, 1.2, 0.3], center: true}), [4.0, 4.6, -4.9]);
const uf_wall_front_final = difference(difference(difference(uf_wall_front, uf_win1), uf_win2), uf_win3);

const uf_bwin1 = translate(cube({size: [1.2, 1.2, 0.3], center: true}), [-2.0, 4.6, 4.9]);
const uf_bwin2 = translate(cube({size: [1.2, 1.2, 0.3], center: true}), [2.5, 4.6, 4.9]);
const uf_wall_back_final = difference(difference(uf_wall_back, uf_bwin1), uf_bwin2);

// Gable roof — two sloped panels, 30deg pitch
const roof_left = translate(rotate(cube({size: [12.6, 0.08, 6.2], center: true}), [0.52, 0, 0]), [0, 7.5, -2.5]);
const roof_right = translate(rotate(cube({size: [12.6, 0.08, 6.2], center: true}), [-0.52, 0, 0]), [0, 7.5, 2.5]);

// Front porch roof and posts
const porch_post_l = translate(cube({size: [0.12, 2.5, 0.12], center: true}), [-1.0, 1.55, -5.8]);
const porch_post_r = translate(cube({size: [0.12, 2.5, 0.12], center: true}), [1.0, 1.55, -5.8]);
const porch_roof = translate(rotate(cube({size: [2.8, 0.06, 1.4], center: true}), [0.15, 0, 0]), [0, 2.9, -5.5]);
const porch_floor = translate(cube({size: [2.4, 0.12, 1.2], center: true}), [0, 0.36, -5.5]);

scene = union(
  foundation,
  gf_wall_front_final, gf_wall_back_final, gf_wall_left, gf_wall_right,
  floor1,
  uf_wall_front_final, uf_wall_back_final, uf_wall_left, uf_wall_right,
  roof_left, roof_right,
  porch_post_l, porch_post_r, porch_roof, porch_floor
);
